const aiOutput = $input.first().json;
const baseData = $('Prepare for AI').first().json;

try {
  const cleanedText = aiOutput.output
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  const parsedJson = JSON.parse(cleanedText);

  return [{
    json: {
      // От AI
      ...parsedJson,

      // Метаданные из Prepare for AI
      fullText: baseData._originalFullText || '',
      webViewLink: baseData.webViewLink || '',
      fileName: baseData.fileName || '',
      contentType: baseData.contentType || '',
      postAuthor: baseData.postAuthor || '',
      senderComment: baseData.senderComment || '',
      originalPostText: baseData.originalPostText || '',
      groupId: baseData.groupId || '',
      sender: baseData.sender || '',
      extractedUrl: baseData.extractedUrl || null,
      sourceUrl: baseData.sourceUrl || '',

     additionalUrls: baseData.additionalUrls || '',

      // Fallback
      articleTitle: parsedJson.originalTitle || baseData.articleTitle || 'Без названия',

      output: undefined
    }
  }];
} catch (error) {
  return [{
    json: {
      parseError: `Ошибка: ${error.message}`,
      rawOutput: aiOutput.output,
      ...baseData   // тут уже будет linkContent
    }
  }];
}

