const item = $input.item.json;

// Список поддерживаемых MIME типов
const supportedTypes = [
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',  // DOCX
  'application/msword'  // DOC (старый формат)
];

// Проверяем, есть ли ФОТО (отправлено как изображение)
if (item.message?.photo) {
  const caption = item.message.caption || '';

  // Если есть текст (caption) - пропускаем с извлечением текста
  if (caption.trim().length > 0) {
    return {
      json: {
        ...item,
        isFileSupported: true,
        hasPhoto: true,
        extractedText: caption,
        mimeType: null,
        fileType: 'фото с текстом'
      }
    };
  }

  // Если фото БЕЗ текста - отклоняем
  return {
    json: {
      ...item,
      isFileSupported: false,
      hasPhoto: true,
      mimeType: 'image/jpeg',
      fileName: 'Фото',
      fileType: 'изображение'
    }
  };
}

// Проверяем, есть ли документ
if (item.message?.document) {
  const mimeType = item.message.document.mime_type;
  const fileName = item.message.document.file_name || '';
  const caption = item.message.caption || '';

  // Проверяем, поддерживается ли формат
  const isSupported = supportedTypes.includes(mimeType);

  // Определяем тип файла для сообщения
  let fileType = 'неизвестный';
  if (mimeType.includes('image')) fileType = 'изображение';
  else if (mimeType.includes('epub')) fileType = 'EPUB';
  else if (mimeType.includes('video')) fileType = 'видео';
  else if (mimeType.includes('audio')) fileType = 'аудио';
  else if (mimeType.includes('officedocument.wordprocessingml.document')) fileType = 'DOCX';
  else if (mimeType === 'application/msword') fileType = 'DOC';
  else fileType = mimeType;

  return {
    json: {
      ...item,
      isFileSupported: isSupported,
      mimeType: mimeType,
      fileName: fileName,
      fileType: fileType,
      extractedText: caption.trim().length > 0 ? caption : null
    }
  };
}

// Если это не файл и не фото (текст, ссылка) - пропускаем дальше
return {
  json: {
    ...item,
    isFileSupported: true,
    mimeType: null,
    fileType: null
  }
};

