const item = $input.item.json;
const error = item.error || {};
const message = error.message || '';
const httpCode = error.httpCode || '';

let errorType = 'Неизвестная ошибка';
let errorDetails = '';
let canRetry = false;

// Классифицируем ошибку
if (httpCode === '429' || message.includes('rate limit')) {
  errorType = 'Превышен лимит запросов';
  errorDetails = 'Airtable API ограничивает количество запросов. Попробуйте через 30 секунд.';
  canRetry = true;

} else if (httpCode === '503' || message.includes('temporarily unavailable')) {
  errorType = 'Сервис временно недоступен';
  errorDetails = 'Airtable испытывает технические проблемы. Попробуйте через несколько минут.';
  canRetry = true;

} else if (httpCode === '401' || httpCode === '403') {
  errorType = 'Ошибка авторизации';
  errorDetails = 'Проверьте токен Airtable в настройках бота.';
  canRetry = false;

} else if (httpCode === '422' || message.includes('invalid request')) {
  errorType = 'Неверный формат данных';
  errorDetails = 'AI вернул данные в неправильном формате. Попробуйте другую ссылку.';
  canRetry = false;

} else if (httpCode === '413' || message.includes('too large')) {
  errorType = 'Слишком много данных';
  errorDetails = 'Текст или резюме получились слишком длинными.';
  canRetry = false;

} else if (message.includes('timeout')) {
  errorType = 'Превышено время ожидания';
  errorDetails = 'Airtable не ответил вовремя. Попробуйте еще раз.';
  canRetry = true;
}

return {
  json: {
    ...item,
    errorType,
    errorDetails,
    canRetry,
    originalError: message
  }
};

