    rawText: meta.rawText
  }
};

// Универсальный парсер для всех типов сообщений
const item = $input.item.json;

// --- 1️⃣ Собираем весь возможный текст ---
let text =
  item.message?.text ||
  item.message?.caption ||
  '';

// Очищаем для обработки
let cleanedText = text.replace(/\r/g, '').trim();

// --- 1b️⃣ Определяем исходный текст для Airtable (без "голых" ссылок) ---
// Убираем все URL из текста
const textWithoutUrls = cleanedText.replace(/https?:\/\/[^\s]+/gi, '').trim();

// Если после удаления ссылок ничего не осталось — считаем, что "исходного текста" нет
// (случай, когда сообщение = только одна или несколько ссылок)
const rawText = textWithoutUrls.length === 0 ? '' : cleanedText;

// Дальше для парсинга ссылок и заголовков работаем с cleanedText
text = cleanedText;

// --- 2️⃣ Извлекаем ВСЕ ссылки из текста и entities ---

// 2a. Ссылки, написанные явно в тексте
const urlPattern = /https?:\/\/[^\s]+/gi;
let allUrls = text.match(urlPattern) || [];

// 2b. Ссылки из entities (url, text_link)
const entities = item.message?.entities || item.message?.caption_entities || [];

for (const entity of entities) {
  if (entity.type === 'url') {
    // URL прямо в тексте
    const start = entity.offset;
    const end = entity.offset + entity.length;
    const urlFromText = text.substring(start, end);
    allUrls.push(urlFromText);
  } else if (entity.type === 'text_link' && entity.url) {
    // Гиперссылка вида [текст](url)
    allUrls.push(entity.url);
  }
}

// Убираем дубликаты
allUrls = Array.from(new Set(allUrls));


// Фильтруем ссылки (убираем Telegram-ссылки)
const filteredUrls = allUrls.filter(url =>
  !url.includes('t.me/') &&
  url.length > 15
);

// --- 3️⃣ Определяем главную и дополнительные ссылки ---
const mainUrl = filteredUrls.length > 0 ? filteredUrls[0] : null;
const additionalUrls = filteredUrls.length > 1
  ? filteredUrls.slice(1).join('\n')
  : null;

// --- 3a️⃣ ИСПРАВЛЕННАЯ ЛОГИКА: Определяем Источник с правильными приоритетами ---
let sourceUrl = null;
let telegramSourceUrl = null; // Дополнительно сохраним Telegram-источник

// Сначала проверяем: это форвард из канала/чата?
if (item.message?.forward_from_chat?.username && item.message?.forward_from_message_id) {
  // ПРИОРИТЕТ 1: Форвард из публичного Telegram-канала → ссылка на канал
  telegramSourceUrl = `https://t.me/${item.message.forward_from_chat.username}/${item.message.forward_from_message_id}`;
  sourceUrl = telegramSourceUrl; // Для каналов Telegram = приоритетный источник

} else if (item.message?.forward_from_chat?.title) {
  // ПРИОРИТЕТ 2: Форвард из приватного канала → название канала
  telegramSourceUrl = `Канал: ${item.message.forward_from_chat.title}`;
  sourceUrl = telegramSourceUrl;

} else if (mainUrl) {
  // ПРИОРИТЕТ 3: Внешняя ссылка (если НЕ форвард из канала)
  sourceUrl = mainUrl;

} else if (item.message?.forward_origin?.sender_user_name) {
  // ПРИОРИТЕТ 4: Форвард от пользователя (скрытый профиль)
  sourceUrl = item.message.forward_origin.sender_user_name;

} else if (item.message?.forward_from?.username) {
  // ПРИОРИТЕТ 5: Форвард от обычного пользователя
  sourceUrl = `@${item.message.forward_from.username}`;

} else if (item.message?.forward_from?.first_name) {
  // ПРИОРИТЕТ 6: Имя пользователя
  sourceUrl = item.message.forward_from.first_name;

} else if (item.message?.chat?.username && item.message?.message_id) {
  // ПРИОРИТЕТ 7: Обычное сообщение в публичном чате
  sourceUrl = `https://t.me/${item.message.chat.username}/${item.message.message_id}`;
}


// --- 4️⃣ Извлекаем домен из главной ссылки ---
let sourceDomain = null;
if (mainUrl) {
  try {
    const url = new URL(mainUrl);
    sourceDomain = url.hostname.replace('www.', '');
  } catch (e) {
    sourceDomain = mainUrl.split('/')[2] || null;
  }
}

// --- 5️⃣ Пытаемся извлечь название статьи из текста ---
let articleTitle = null;

// ПРИОРИТЕТ 1: Команда "save"
const saveMatch = text.match(/save\s+(.+?)(?=\s*https?:\/\/|$)/i);
if (saveMatch) {
  articleTitle = saveMatch[1].trim();
}

// ПРИОРИТЕТ 2: Первая строка до ссылки (или первая строка текста)
if (!articleTitle && text.length > 0) {
  // Ищем первую непустую строку
  const lines = text.split('\n').filter(l => l.trim().length > 0);

  if (lines.length > 0) {
    // Берём первую строку как заголовок
    const firstLine = lines[0].trim();

    // Проверяем, что это не сама ссылка
    if (!firstLine.match(/^https?:\/\//i)) {
      articleTitle = firstLine;
    } else if (lines.length > 1) {
      // Если первая строка = ссылка, берём вторую
      articleTitle = lines[1].trim();
    }
  }
}

// ПРИОРИТЕТ 3: Текст перед первой ссылкой (если есть ссылка в середине)
if (!articleTitle && mainUrl) {
  const beforeUrl = text.split(mainUrl)[0].trim();
  const lines = beforeUrl.split('\n').filter(l => l.trim().length > 0);
  if (lines.length > 0) {
    articleTitle = lines[lines.length - 1].trim();
  }
}

// Очистка названия
if (articleTitle) {
  articleTitle = articleTitle
    .replace(/^(forwarded from|переслано от)[^\n]*/i, '')
    .replace(/^[:\-—–\s]+|[:\-—–\s]+$/g, '')
    .replace(/^["«']+|["»']+$/g, '')
    .replace(/^[•\-\s]+/, '') // убираем буллеты
    .trim();

  // Ограничиваем длину
  if (articleTitle.length > 200) {
    articleTitle = articleTitle.substring(0, 200) + '...';
  }

  // Если заголовок слишком короткий (<3 символов) - убираем
  if (articleTitle.length < 3) {
    articleTitle = null;
  }
}


// --- 6️⃣ Определяем отправителя и автора ---
let sender = null;
let postAuthor = null;
let originalPostText = '';
let senderComment = '';

// ЛОГИКА ОПРЕДЕЛЕНИЯ ОТПРАВИТЕЛЯ:
// При двойной пересылке структура такая:
// - message.from = последний пересыльщик (я)
// - message.forward_from = промежуточный пересыльщик (Denis)
// - message.forward_origin = оригинальный автор (A K)

// ОТПРАВИТЕЛЬ - приоритет на промежуточного пересыльщика
// Если есть forward_from → это тот, кто переслал ПЕРВЫМ (Denis)
// Если нет → тогда тот, кто написал в группу (message.from)

if (item.message?.forward_from?.first_name) {
  // ПРИОРИТЕТ 1: Промежуточный пересыльщик (Denis F.)
  sender = item.message.forward_from.first_name;
  if (item.message.forward_from.username) {
    sender += ` (@${item.message.forward_from.username})`;
  }
} else if (item.message?.from?.first_name) {
  // ПРИОРИТЕТ 2: Прямой отправитель (вы)
  sender = item.message.from.first_name;
  if (item.message.from.username) {
    sender += ` (@${item.message.from.username})`;
  }
}

// АВТОР ОРИГИНАЛЬНОГО ПОСТА - только для форвардов
const isForwardedMessage = !!(
  item.message?.forward_origin?.sender_user_name ||
  item.message?.forward_from?.first_name ||
  item.message?.forward_from_chat?.title
);

if (isForwardedMessage) {
  // Это форвард - определяем автора оригинального поста

  if (item.message?.forward_origin?.sender_user_name) {
    // Случай 1: Скрытый профиль (A K)
    postAuthor = item.message.forward_origin.sender_user_name;

  } else if (item.message?.forward_origin?.sender_user?.first_name) {
    // Случай 2: Публичный профиль в forward_origin
    postAuthor = item.message.forward_origin.sender_user.first_name;
    if (item.message.forward_origin.sender_user.username) {
      postAuthor += ` (@${item.message.forward_origin.sender_user.username})`;
    }

  } else if (item.message?.forward_from_chat?.title) {
    // Случай 3: Форвард из канала
    postAuthor = item.message.forward_from_chat.title;

  } else if (item.message?.forward_from?.first_name && !sender) {
    // Случай 4: forward_from = оригинальный автор (НЕ промежуточный)
    // Это работает, если НЕТ двойной пересылки
    postAuthor = item.message.forward_from.first_name;
    if (item.message.forward_from.username) {
      postAuthor += ` (@${item.message.forward_from.username})`;
    }
  }
}

// РАЗЛИЧАЕМ КОММЕНТАРИЙ И ОРИГИНАЛЬНЫЙ ТЕКСТ
if (isForwardedMessage) {
  // Это форвард
  const messageText = item.message?.text || item.message?.caption || '';

  // Проверяем: есть ли у forwarded message собственный текст?
  const forwardedText = 
    item.message?.forward_origin?.text || 
    item.message?.forward_origin?.caption || 
    '';

  if (forwardedText) {
    // Случай 1: Telegram передал оригинальный текст
    originalPostText = forwardedText;
    senderComment = messageText.replace(forwardedText, '').trim();

  } else if (messageText.length > 0) {
    // Случай 2: Есть текст, но непонятно — это комментарий или оригинал?
    // Эвристика: если текст содержит ссылки → скорее всего оригинал поста

    if (filteredUrls.length > 0) {
      // Есть ссылки → вероятно, это текст из оригинального поста
      originalPostText = messageText;
      senderComment = '';
    } else {
      // Нет ссылок → вероятно, комментарий отправителя
      originalPostText = '';
      senderComment = messageText;
    }

  } else {
    // Случай 3: Форвард без текста (например, только медиа)
    originalPostText = '';
    senderComment = '';
  }

} else {
  // Это НЕ форвард — весь текст это сообщение отправителя
  senderComment = item.message?.text || item.message?.caption || '';
  originalPostText = '';
}



// --- 7️⃣ ОПРЕДЕЛЯЕМ ТИП МАТЕРИАЛА ---
let contentType = null;

const hasPDF = item.message?.document?.mime_type === 'application/pdf';
const hasPhoto = !!item.message?.photo;
const hasVideo = !!item.message?.video;
const hasDocument = !!item.message?.document && !hasPDF;
const hasText = !!(item.message?.text || item.message?.caption);
const hasLink = filteredUrls.length > 0;

if (hasPDF) {
  contentType = 'PDF';
} else if (isForwardedMessage && (hasDocument || hasPhoto || hasVideo)) {
  contentType = 'Пост + файл';
} else if (isForwardedMessage) {
  contentType = 'Пост Telegram';
} else if (hasLink && hasText) {
  contentType = 'Смешанный';
} else if (hasLink && !hasText) {
  contentType = 'Ссылка';
} else if (hasText) {
  contentType = 'Пост Telegram';
} else {
  contentType = 'Смешанный';
}

// --- 8️⃣ Возвращаем обогащённые данные ---
return {
  json: {
    ...item,

    // 🔹 Ссылка на источник (ИСПРАВЛЕНО: приоритет внешней ссылке)
    sourceUrl,

     // 🔹 Telegram-источник (отдельно, если нужно)
    telegramSourceUrl,

    // 🔹 Первая внешняя ссылка (для Jina и анализа статьи)
    extractedUrl: mainUrl,
    additionalUrls,

    // 🔹 Исходный текст сообщения
    rawText,

    // 🔹 Метаданные
    articleTitle,
    sourceDomain,
    messageDate: item.message?.date || null,
    sender: sender,

    // 🔹 Группировка
    groupId: item._groupId || null,
    timestamp: item._timestamp || null,

    // 🔹 Авторы и комментарии
    postAuthor: postAuthor,
    senderComment: senderComment,
    originalPostText: originalPostText,

    // 🔹 Тип материала
    contentType: contentType
  }
};

// // ✅ Простое решение - берём first item (который пришёл)
